// Build prompt with all slide info for layout selection
const slides = $json.slides;
const slidesSummary = slides.map((s, i) => 
  `Slide ${i+1}: "${s.title}" — ${(s.content || '').substring(0, 100)}...`
).join('\n');

const layoutList = 'cover, section-header, bullets, two-column, comparison, pros-cons, timeline, roadmap, stat-highlight, kpi-grid, quote, image-full, image-left, image-right, code, terminal, table, chart-placeholder, mindmap, pyramid, funnel, process-steps, checklist, team-grid, pricing, faq, demo, video-embed, closing, thank-you, contact';

return [{
  json: {
    ...($input.first().json),
    slides_summary: slidesSummary,
    layout_list: layoutList
  }
}];

// Parse layout selection
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
let layouts = [];
try { layouts = JSON.parse(text); } catch(e) { layouts = []; }
return [{ json: { ...($('Build Layout Prompt').first().json), layouts } }];

